@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@using BlazorNotifications.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    // Runs during SSR *and* when the component becomes interactive.
    // On SSR this seeds the prerendered HTML; on interactive init the
    // framework replays the same parameter state so we skip re-fetching.
    protected override void OnInitialized()
    {
        _notifications = NotificationService.GetAll();
    }

    // Called only once, after the component is interactive in the browser.
    // Safe place to start the polling loop — will NOT run during SSR.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        // Track the highest Id we already have so we only fetch new ones.
        var lastId = _notifications.Count > 0
            ? _notifications.Max(n => n.Id)
            : 0;

        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                // Simulate an external notification arriving.
                NotificationService.SimulateIncoming();

                var newer = NotificationService.GetSince(lastId);
                if (newer.Count > 0)
                {
                    _notifications.AddRange(newer);
                    lastId = newer.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                // Expected on disposal — exit cleanly.
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

